const LATIN_TO_CYRILLIC: Record<string, string> = {
  'A': 'А', 'B': 'В', 'C': 'С', 'E': 'Е', 'H': 'Н', 'K': 'К', 'M': 'М',
  'O': 'О', 'P': 'Р', 'T': 'Т', 'X': 'Х', 'Y': 'У',
  'a': 'а', 'c': 'с', 'e': 'е', 'o': 'о', 'p': 'р', 'x': 'х', 'y': 'у',
  'k': 'к', 'n': 'н', 'b': 'ь', // частые ошибки NVIDIA
}

/** Регулярка для CJK-символов (китайские/японские/корейские) */
const CJK_REGEX = /[\u4E00-\u9FFF\u3400-\u4DBF\u3000-\u303F\u3040-\u309F\u30A0-\u30FF\uAC00-\uD7AF]/g

/**
 * Очищает русский текст от мусора AI-моделей:
 * 1. Удаляет CJK-символы ("Матрица混ения" → "Матрицаения")
 * 2. Заменяет латинские гомоглифы на кириллицу в смешанных словах
 */
export function sanitizeRussianContent(text: string): string {
  // 1. Удаляем CJK-символы (китайские, японские и т.д.)
  let result = text.replace(CJK_REGEX, '')

  // 2. Исправляем гомоглифы: находим слова, где смешаны кириллица и латиница
  // Не трогаем: чисто латинские слова, код, URL, markdown-разметку
  result = result.replace(/[\wа-яёА-ЯЁ]+/g, (word) => {
    const hasCyrillic = /[а-яёА-ЯЁ]/.test(word)
    const hasLatin = /[a-zA-Z]/.test(word)

    // Только смешанные слова — латиницу в кириллицу
    if (!hasCyrillic || !hasLatin) return word

    return word.split('').map(ch => LATIN_TO_CYRILLIC[ch] ?? ch).join('')
  })

  return result
}

