  'a': 'а', 'c': 'с', 'e': 'е', 'o': 'о', 'p': 'р', 'x': 'х', 'y': 'у', 'k': 'к',
}

const CJK_REGEX = /[\u4E00-\u9FFF\u3400-\u4DBF\u3000-\u303F\u3040-\u309F\u30A0-\u30FF\uAC00-\uD7AF]/g

/** Очищает текст: CJK удаляет, в смешанных словах гомоглифы→кир, остальную латиницу удаляет */
function sanitizeContent(text: string): string {
  let result = text.replace(CJK_REGEX, '')
  result = result.replace(/[\wа-яёА-ЯЁ]+/g, (word) => {
    const hasCyrillic = /[а-яёА-ЯЁ]/.test(word)
    const hasLatin = /[a-zA-Z]/.test(word)
    if (!hasCyrillic || !hasLatin) return word
    return word.split('').map(ch => {
      if (LATIN_TO_CYRILLIC[ch]) return LATIN_TO_CYRILLIC[ch]
      if (/[a-zA-Z]/.test(ch)) return '' // неоднозначную латиницу удаляем
      return ch
    }).join('')
  })
  return result
}"}]}

